def solve(grid):
    import numpy as np
    g = np.array(grid)
    H, W = g.shape
    output = g.copy()

    # Find dead ends of the 8-network
    dead_ends = []
    for r in range(H):
        for c in range(W):
            if g[r,c] == 8:
                neighbors = 0
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and g[nr,nc] in [8, 5, 9]:
                        neighbors += 1
                if neighbors == 1:
                    dead_ends.append((r, c))

    # For each dead end, find endpoint position and direction
    def get_endpoint(de_r, de_c):
        for ndr, ndc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = de_r + ndr, de_c + ndc
            if 0 <= nr < H and 0 <= nc < W and g[nr, nc] in [8, 5, 9]:
                ep_dir = (-ndr, -ndc)
                ep_r = de_r + ep_dir[0] * 2
                ep_c = de_c + ep_dir[1] * 2
                return ep_r, ep_c, ep_dir
        return None

    # Wire tracing (always go straight when possible)
    def trace_wire(start_r, start_c, start_dir):
        r, c = start_r, start_c
        dr, dc = start_dir
        visited = {(r, c)}
        for _ in range(500):
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W and g[nr, nc] in [8, 5, 9] and (nr, nc) not in visited:
                r, c = nr, nc
                visited.add((r, c))
                continue
            turned = False
            for ndr, ndc in [(-1,0),(1,0),(0,-1),(0,1)]:
                if (ndr, ndc) == (-dr, -dc) or (ndr, ndc) == (dr, dc):
                    continue
                nnr, nnc = r + ndr, c + ndc
                if 0 <= nnr < H and 0 <= nnc < W and g[nnr, nnc] in [8, 5, 9] and (nnr, nnc) not in visited:
                    dr, dc = ndr, ndc
                    r, c = nnr, nnc
                    visited.add((r, c))
                    turned = True
                    break
            if not turned:
                break
        return r, c

    # Build endpoint info for each dead end
    endpoints = {}  # de -> (ep_r, ep_c, ep_dir, color, pattern_type)
    for de_r, de_c in dead_ends:
        result = get_endpoint(de_r, de_c)
        if result:
            ep_r, ep_c, ep_dir = result
            # Detect current content at endpoint
            color = 0
            ptype = 'Empty'
            if 0 <= ep_r-1 and ep_r+1 < H and 0 <= ep_c-1 and ep_c+1 < W:
                block = g[ep_r-1:ep_r+2, ep_c-1:ep_c+2]
                vals = set(block.flatten()) - {0}
                if len(vals) == 1 and list(vals)[0] not in [5, 8, 9]:
                    ptype = 'Solid'
                    color = int(list(vals)[0])
                else:
                    # Check for cross patterns
                    for cr in range(ep_r-1, ep_r+2):
                        for cc in range(ep_c-1, ep_c+2):
                            if 0 <= cr < H and 0 <= cc < W and g[cr,cc] not in [0, 5, 8, 9]:
                                color = int(g[cr,cc])
                                ptype = 'Cross'
            endpoints[(de_r, de_c)] = (ep_r, ep_c, ep_dir, color, ptype)

    # Pair dead ends by wire tracing
    pairs = {}
    for de_r, de_c in dead_ends:
        ep_r, ep_c, ep_dir, color, ptype = endpoints[(de_r, de_c)]
        net_dir = (-ep_dir[0], -ep_dir[1])
        end_r, end_c = trace_wire(de_r, de_c, net_dir)
        for de2_r, de2_c in dead_ends:
            if (de2_r, de2_c) != (de_r, de_c) and de2_r == end_r and de2_c == end_c:
                pairs[(de_r, de_c)] = (de2_r, de2_c)
                break

    # Determine which side gets Plus and which gets X
    # Group by direction
    groups = {}
    for de in dead_ends:
        ep_r, ep_c, ep_dir, color, ptype = endpoints[de]
        dir_key = ep_dir
        if dir_key not in groups:
            groups[dir_key] = []
        groups[dir_key].append(de)

    # The side with solid blocks gets Plus
    plus_dir = None
    x_dir = None
    for dir_key, des_in_group in groups.items():
        for de in des_in_group:
            if endpoints[de][4] == 'Solid':
                plus_dir = dir_key
                break
        if plus_dir:
            break

    for dir_key in groups:
        if dir_key != plus_dir:
            x_dir = dir_key

    # Assign colors: propagate from known endpoints to their pairs
    # First, collect all known colors
    for de in dead_ends:
        ep_r, ep_c, ep_dir, color, ptype = endpoints[de]
        if color != 0 and de in pairs:
            paired = pairs[de]
            p_ep_r, p_ep_c, p_ep_dir, p_color, p_ptype = endpoints[paired]
            if p_color == 0:
                endpoints[paired] = (p_ep_r, p_ep_c, p_ep_dir, color, p_ptype)

    # Build output
    # First, clear all solid blocks
    for de in dead_ends:
        ep_r, ep_c, ep_dir, color, ptype = endpoints[de]
        if ptype == 'Solid':
            for dr in range(-1, 2):
                for dc in range(-1, 2):
                    output[ep_r+dr, ep_c+dc] = 0

    # Place cross patterns
    for de in dead_ends:
        ep_r, ep_c, ep_dir, color, ptype = endpoints[de]
        if color == 0:
